class TTLCache:
    def __init__(self, capacity, ttl, time_fn=None):
        self.capacity = capacity
        self.ttl = ttl
        self.store = {}
        self.order = []

    def get(self, key):
        if key in self.store and self.store[key][1] - self.time_fn() <= self.ttl:
            return self.store[key][0]
        return None

    def put(self, key, value):
        now = self.time_fn()
        if key in self.store and len(self.store) >= self.capacity:
            oldest = self.order.pop(0)  # Bug: FIFO, not LRU
            del self.store[oldest]
        self.store[key] = (value, now)
        self.order.append(key)

